function checkMethodSizeLimits(content, sectionType) {
  const violations = [];
  const codeBlocks = extractCodeBlocks(content);
  const funcPattern = /(?:func |function |def |fn |fun |public |private |protected |internal |static )*(?:func|function|def|fn|fun|method)\s+(\w+)/;
  for (const codeBlock of codeBlocks) {
    const lines = codeBlock.split("\n");
    let currentFuncName = null;
    let funcStartLine = 0;
    let braceDepth = 0;
    let inFunction = false;
    for (let index = 0; index < lines.length; index++) {
      const line = lines[index];
      if (!inFunction) {
        const match = line.match(funcPattern);
        if (match) {
          currentFuncName = match[1] ?? "anonymous";
          funcStartLine = index;
          inFunction = true;
          braceDepth = 0;
        }
      }
      if (inFunction) {
        braceDepth += (line.match(/\{/g) || []).length;
        braceDepth -= (line.match(/\}/g) || []).length;
        if (braceDepth <= 0 && line.includes("}")) {
          const funcLineCount = index - funcStartLine + 1;
          if (funcLineCount > 30) {
            violations.push(makeViolation("method_size_limits", sectionType, `Code example shows function '${currentFuncName}' spanning ${funcLineCount} lines \u2014 extract logic into smaller functions. Methods should be ~30 lines max in PRD examples.`, currentFuncName));
          }
          inFunction = false;
          currentFuncName = null;
        }
      }
    }
  }
  return violations;
}
